import java.util.Scanner;

public class SecureBufferCopy {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Proper bounds checking before copying user input into buffer
        byte[] buffer = new byte[10]; // Buffer with limited size

        if (userInput.length() > buffer.length) {
            System.out.println("User input exceeds buffer size. Truncating input to fit buffer.");
            System.arraycopy(userInput.getBytes(), 0, buffer, 0, buffer.length);
        } else {
            System.arraycopy(userInput.getBytes(), 0, buffer, 0, userInput.length());
        }

        System.out.println("User input copied into buffer: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
